# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
from urllib.parse import urlparse, parse_qs
import boto3

def lambda_handler(event, context):
    # Get search parameters from API Gateway event
    query = parse_qs(urlparse(event['path']).query)
    
    try:
        host, db_user, db_password = get_db_creds()
        
        conn = pymysql.connect(
            host=host,
            user=db_user,
            password=db_password,
            database='mydatabase'
        )
        
        cursor = conn.cursor(pymysql.cursors.DictCursor)

        # Build dynamic SQL query based on search parameters
        sql_query = "SELECT * FROM products"
        where_clause = ""

        if 'name' in query:
            where_clause += " AND name LIKE %s"
            params = (query['name'][0],)
        
        if 'category' in query:
            if where_clause:
                where_clause += " OR category = %s"
            else:
                where_clause += "category = %s"
            params += (query['category'][0],)

        if 'price_range' in query:
            min_price, max_price = map(float, query['price_range'])
            if where_clause:
                where_clause += " AND price BETWEEN %s AND %s"
            else:
                where_clause += "price BETWEEN %s AND %s"
            params += (min_price, max_price)

        if where_clause:
            sql_query += " WHERE " + where_clause

        cursor.execute(sql_query, params)
        
        products = cursor.fetchall()
        
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    
    except Exception as e:
        print("Error: ", str(e))
        return {
            'statusCode': 500
        }

def get_db_creds():
    rds_instance_id = 'your-rds-instance-id'
    db_instance_arn = f"arn:aws:rds:{boto3.Session().region_name}:{boto3.Session().account_id}:instance:{rds_instance_id}"
    dynamodb = boto3.client('dynamodb')
    response = dynamodb.get_credentials_for_db_instance(DBInstanceId=db_instance_arn)
    return response['Credentials']